package com.example.myapplication

import android.util.Log
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.setValue
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.launch

class DeviceViewModel : ViewModel() {
    var devices by mutableStateOf(emptyList<DeviceData>())
        private set
    var isLoading by mutableStateOf(true)
        private set
    var selectedDevice by mutableStateOf<DeviceData?>(null)
        private set

    init {
        fetchDevices()
    }

    private fun fetchDevices() {
        viewModelScope.launch {
            try {
                val response = RetrofitClient.service.getDevices()
                devices = response.devices ?: emptyList()
            } catch (e: Exception) {
                Log.e("DeviceAPI", "Error fetching devices", e)
            } finally {
                isLoading = false
            }
        }
    }

    fun selectDevice(device: DeviceData) {
        selectedDevice = device
    }

    fun deselectDevice() {
        selectedDevice = null
    }

    fun getDeviceById(id: String?): DeviceData? {
        return devices.find { it.id == id }
    }
}

